'use client'
import { useState, useRef, useEffect } from 'react'
import Card from '../../../components/ui/Card'
import Button from '../../../components/ui/Button'
import { Send, Bot, User, Sparkles } from 'lucide-react'
import { formatDateTime } from '../../../lib/utils'
import type { ChatMessage } from '../../../lib/types'

const suggestedQuestions = [
  'Am I eligible for disability pension?',
  'What documents do I need for ECHS card?',
  'How do I track my application status?',
  'What is the SLA for grievance resolution?',
]

// Dummy AI response — will connect to LangChain + Ollama later
async function getAIResponse(message: string): Promise<string> {
  await new Promise((res) => setTimeout(res, 1200))
  const responses: Record<string, string> = {
    'pension':    'For disability pension, you need to submit: Discharge Certificate, Medical Board Report, PPO, and Service Record. The processing time is 30 days.',
    'echs':       'For ECHS card, required documents are: Discharge Certificate, PPO copy, Passport size photo, and ID proof. Visit your nearest ECHS polyclinic.',
    'track':      'You can track your application status under the Benefits section. Each application shows real-time status with a timeline.',
    'grievance':  'Grievances are resolved within 30 days as per SLA. If not resolved, they are automatically escalated to senior officers.',
    'default':    'I am the VeerSeva AI Assistant. I can help you with information about pension, medical benefits, education schemes, housing loans, and resettlement programs. How can I assist you today?',
  }
  const lower = message.toLowerCase()
  if (lower.includes('pension'))   return responses.pension
  if (lower.includes('echs') || lower.includes('medical')) return responses.echs
  if (lower.includes('track') || lower.includes('status')) return responses.track
  if (lower.includes('grievance')) return responses.grievance
  return responses.default
}

export default function AssistantPage() {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id:        '0',
      role:      'assistant',
      content:   'Jai Hind! 🎖️ I am VeerSeva AI Assistant. I am here to help you with information about your veteran benefits, pension, medical schemes, and more. How can I help you today?',
      timestamp: new Date().toISOString(),
    },
  ])
  const [input,   setInput]   = useState('')
  const [loading, setLoading] = useState(false)
  const bottomRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  async function handleSend(text?: string) {
    const msg = (text ?? input).trim()
    if (!msg) return

    const userMsg: ChatMessage = {
      id:        Date.now().toString(),
      role:      'user',
      content:   msg,
      timestamp: new Date().toISOString(),
    }

    setMessages((prev) => [...prev, userMsg])
    setInput('')
    setLoading(true)

    const response = await getAIResponse(msg)

    const aiMsg: ChatMessage = {
      id:        (Date.now() + 1).toString(),
      role:      'assistant',
      content:   response,
      timestamp: new Date().toISOString(),
    }

    setMessages((prev) => [...prev, aiMsg])
    setLoading(false)
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  return (
    <div className="flex flex-col h-[calc(100vh-8rem)] space-y-4">

      {/* Header */}
      <div className="flex items-center gap-3">
        <div className="w-10 h-10 bg-purple-600 rounded-xl flex items-center justify-center">
          <Bot size={22} className="text-white" />
        </div>
        <div>
          <h1 className="text-xl font-bold text-gray-900">AI Assistant</h1>
          <p className="text-gray-500 text-xs flex items-center gap-1">
            <Sparkles size={11} /> Powered by Llama 3 via Ollama
          </p>
        </div>
      </div>

      {/* Chat window */}
      <Card padding="none" className="flex-1 flex flex-col overflow-hidden">

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {messages.map((msg) => (
            <div
              key={msg.id}
              className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
            >
              {/* Avatar */}
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${
                msg.role === 'assistant' ? 'bg-purple-100' : 'bg-green-700'
              }`}>
                {msg.role === 'assistant'
                  ? <Bot  size={16} className="text-purple-600" />
                  : <User size={16} className="text-white" />
                }
              </div>

              {/* Bubble */}
              <div className={`max-w-sm lg:max-w-md ${msg.role === 'user' ? 'items-end' : 'items-start'} flex flex-col`}>
                <div className={`px-4 py-3 rounded-2xl text-sm leading-relaxed ${
                  msg.role === 'user'
                    ? 'bg-green-700 text-white rounded-tr-sm'
                    : 'bg-gray-100 text-gray-800 rounded-tl-sm'
                }`}>
                  {msg.content}
                </div>
                <span className="text-xs text-gray-400 mt-1 px-1">
                  {formatDateTime(msg.timestamp)}
                </span>
              </div>
            </div>
          ))}

          {/* Loading bubble */}
          {loading && (
            <div className="flex gap-3">
              <div className="w-8 h-8 rounded-full bg-purple-100 flex items-center justify-center">
                <Bot size={16} className="text-purple-600" />
              </div>
              <div className="bg-gray-100 rounded-2xl rounded-tl-sm px-4 py-3">
                <div className="flex gap-1">
                  <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                  <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                  <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                </div>
              </div>
            </div>
          )}
          <div ref={bottomRef} />
        </div>

        {/* Suggested questions */}
        {messages.length === 1 && (
          <div className="px-4 pb-3">
            <p className="text-xs text-gray-400 mb-2">Suggested questions:</p>
            <div className="flex flex-wrap gap-2">
              {suggestedQuestions.map((q) => (
                <button
                  key={q}
                  onClick={() => handleSend(q)}
                  className="px-3 py-1.5 bg-purple-50 text-purple-700 text-xs rounded-full border border-purple-100 hover:bg-purple-100 transition-colors"
                >
                  {q}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Input bar */}
        <div className="border-t border-gray-100 p-4 flex gap-3">
          <textarea
            rows={1}
            placeholder="Ask about your benefits, pension, medical schemes..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            className="flex-1 px-4 py-2.5 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-purple-400 resize-none"
          />
          <Button
            variant="secondary"
            onClick={() => handleSend()}
            disabled={!input.trim() || loading}
            className="bg-purple-600 hover:bg-purple-700 px-4"
          >
            <Send size={16} />
          </Button>
        </div>
      </Card>

    </div>
  )
}
